var ballGeometry = new api.THREE.SphereGeometry(1, 24, 24);
                var ballMaterial = new api.THREE.MeshPhongMaterial({ color: 0xE8593C });
                var ball = new api.THREE.Mesh(ballGeometry, ballMaterial);
                api.group.add(ball);
                return {
                  update: function(t) {
                    var cycle = (t * 0.01) % (2 * Math.PI);
                    var scale = 0.25 + 0.75 * (0.5 + 0.5 * Math.cos(cycle));
                    ball.scale.set(scale, scale, scale);
                    ball.rotation.y = t * 0.02;
                  }
                };

var elapsed = 0;
        return {
          draw: function(ctx, W, H, t, dt) {
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, W, H);

            var fallDuration = 1.4;
            var cycle = fallDuration + 0.8;
            elapsed += Math.min(dt || 0, 0.05);
            if (elapsed > cycle) { elapsed -= cycle; }
            var time = Math.min(elapsed, fallDuration);
            var progress = time / fallDuration;
            var y = 40 + (H - 80) * progress * progress;
            y = Math.min(y, H - 40);

            ctx.fillStyle = '#333';
            ctx.font = 'bold 13px Arial';
            ctx.fillText('Real ball (spins, has size)', 20, 25);
            ctx.fillText('Point-mass model (just falls)', W / 2 + 20, 25);

            // Real ball: spins visibly, has a seam so you can see rotation
            var rx = W * 0.28;
            ctx.save();
            ctx.translate(rx, y);
            ctx.rotate(t * 0.05);
            ctx.fillStyle = '#DC2626';
            ctx.beginPath();
            ctx.arc(0, 0, 18, 0, Math.PI * 2);
            ctx.fill();
            ctx.strokeStyle = '#7F1D1D';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(-18, 0);
            ctx.lineTo(18, 0);
            ctx.stroke();
            ctx.restore();

            // Model: a plain point/dot, no rotation, no size
            var px = W * 0.72;
            ctx.fillStyle = '#111827';
            ctx.beginPath();
            ctx.arc(px, y, 5, 0, Math.PI * 2);
            ctx.fill();

            ctx.fillStyle = '#666';
            ctx.font = '12px Arial';
            ctx.fillText('y = \u00bd g t\u00b2 predicts both just fine', 20, H - 15);
          }
        };

return {
          draw: function(ctx, w, h) {
            ctx.clearRect(0, 0, w, h);
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, w, h);

            var g = 9.8;
            var time = state.time || 0;
            var y = 30 + 0.5 * g * time * time * 6;
            if (y > h - 40) { time = 0; y = 30; }
            state.time = time + 0.03;

            var showModel = !!state.showModel;
            var cx = w / 2;

            if (showModel) {
              ctx.fillStyle = '#111827';
              ctx.beginPath();
              ctx.arc(cx, y, 4, 0, Math.PI * 2);
              ctx.fill();
              ctx.font = 'bold 13px Arial';
              ctx.fillText('Point-mass model: just F = ma, no size or spin', 12, 22);
            } else {
              ctx.save();
              ctx.translate(cx, y);
              ctx.rotate(time * 4);
              ctx.fillStyle = '#DC2626';
              ctx.beginPath();
              ctx.arc(0, 0, 20, 0, Math.PI * 2);
              ctx.fill();
              ctx.strokeStyle = '#7F1D1D';
              ctx.lineWidth = 2;
              ctx.beginPath();
              ctx.moveTo(-20, 0);
              ctx.lineTo(20, 0);
              ctx.stroke();
              ctx.restore();
              ctx.fillStyle = '#111827';
              ctx.font = 'bold 13px Arial';
              ctx.fillText('Real ball: has size, spins, feels air resistance', 12, 22);
            }
          },
          onControlChange: function(id, val) {
            state[id] = val;
          },
          init: function() {
            state.time = 0;
            state.showModel = false;
          }
        };
